mapper.select:
SELECT IFNULL(SUM(progress), 0)
FROM learning_record
WHERE user_id = #{userId}

SELECT IFNULL(SUM(progress), 0)
FROM learning_record
WHERE user_id = #{userId}
AND last_learn_time BETWEEN #{startTime} AND #{endTime}

SELECT COUNT(DISTINCT course_id)
FROM learning_record
WHERE user_id = #{userId}

SELECT user_id, course_id, lesson_id, progress, is_completed, last_learn_time, created_time, updated_time
FROM learning_record
WHERE user_id = #{userId}
ORDER BY last_learn_time DESC
LIMIT #{limit}

update.foreach:
UPDATE learning_record
SET progress = #{record.progress},
    is_completed = #{record.isCompleted},
    last_learn_time = #{record.lastLearnTime},
    updated_time = #{record.updatedTime}
WHERE user_id = #{record.userId}
AND course_id = #{record.courseId}
AND lesson_id = #{record.lessonId}
